import { useState, useEffect, useMemo } from "react";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { useMarket } from "@/lib/MarketContext";
import { fmt, fmtTime } from "@/lib/parseItem";
import { X as XIcon, Check, Bell, BellOff, TrendingUp, TrendingDown, Sparkles, Trash2 } from "lucide-react";
import { useNotifications } from "@/lib/useNotifications";
import { ALERTS_EVENT } from "@/lib/useNotesAlerts";
import { EmptyState } from "@/components/ui/empty-state";
import { Skeleton } from "@/components/ui/skeleton";

const ALERTS_KEY = "castia.alerts";

function readAlerts() {
  try {
    const raw = localStorage.getItem(ALERTS_KEY);
    return raw ? JSON.parse(raw) : {};
  } catch {
    return {};
  }
}

function writeAlerts(alerts) {
  localStorage.setItem(ALERTS_KEY, JSON.stringify(alerts));
  window.dispatchEvent(new CustomEvent(ALERTS_EVENT));
}

export default function AlertsPage() {
  const { market } = useMarket();
  const [alerts, setAlerts] = useState({});
  const [activeTab, setActiveTab] = useState("active");
  const { permission, requestPermission } = useNotifications();

  useEffect(() => {
    const load = () => setAlerts(readAlerts());
    load();
    window.addEventListener(ALERTS_EVENT, load);
    return () => window.removeEventListener(ALERTS_EVENT, load);
  }, []);

  const activeAlerts = useMemo(() => {
    return Object.entries(alerts)
      .filter(([_, a]) => a.enabled && !a.firedAt)
      .map(([key, a]) => ({ key, ...a }));
  }, [alerts]);

  const historyAlerts = useMemo(() => {
    return Object.entries(alerts)
      .filter(([_, a]) => a.firedAt)
      .map(([key, a]) => ({ key, ...a }));
  }, [alerts]);

  const toggleAlert = (key) => {
    const current = alerts[key];
    if (!current) return;
    const updated = { ...current, enabled: !current.enabled };
    writeAlerts({ ...alerts, [key]: updated });
  };

  const removeAlert = (key) => {
    const { [key]: _, ...rest } = alerts;
    writeAlerts(rest);
  };

  const clearHistory = () => {
    const remaining = Object.entries(alerts).filter(([_, a]) => !a.firedAt);
    const newAlerts = Object.fromEntries(remaining);
    writeAlerts(newAlerts);
  };

  const getRow = (key) => market?.rowsByKey?.get(key);

  const alertIcon = (kind) => {
    if (kind === "price_up") return { Icon: TrendingUp, color: "text-emerald-400", bg: "bg-emerald-500/10", border: "border-emerald-500/30" };
    if (kind === "price_down") return { Icon: TrendingDown, color: "text-red-400", bg: "bg-red-500/10", border: "border-red-500/30" };
    return { Icon: Sparkles, color: "text-blue-400", bg: "bg-blue-500/10", border: "border-blue-500/30" };
  };

  const dismissAllActive = () => {
    const remaining = Object.entries(alerts).filter(([_, a]) => a.firedAt);
    const newAlerts = Object.fromEntries(remaining);
    writeAlerts(newAlerts);
  };

  const isLoading = Object.keys(alerts).length === 0;

  return (
    <div className="min-h-screen bg-bg-base text-white">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-4xl mx-auto px-6 md:px-12 lg:px-16">
          <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">/ Price Alerts</div>
          <h1 className="font-heading text-5xl lg:text-7xl tracking-tighter font-black leading-[0.95] mb-8">
            Alert <span className="text-emerald-400">Manager</span>
          </h1>

          <div className="flex items-center gap-1 mb-6">
            <button
              onClick={() => setActiveTab("active")}
              className={`px-4 py-2 text-sm font-mono uppercase tracking-wider border-b-2 transition-colors ${
                activeTab === "active"
                  ? "border-emerald-400 text-emerald-400"
                  : "border-transparent text-zinc-400 hover:text-white"
              }`}
            >
              Active ({activeAlerts.length})
            </button>
            <button
              onClick={() => setActiveTab("history")}
              className={`px-4 py-2 text-sm font-mono uppercase tracking-wider border-b-2 transition-colors ${
                activeTab === "history"
                  ? "border-emerald-400 text-emerald-400"
                  : "border-transparent text-zinc-400 hover:text-white"
              }`}
            >
              History ({historyAlerts.length})
            </button>
            <div className="ml-auto flex items-center gap-2">
              {permission === "granted" ? (
                <span className="inline-flex items-center gap-1.5 px-3 py-1.5 font-mono text-[10px] uppercase tracking-wider bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full">
                  <Bell className="w-3 h-3" /> Notifications on
                </span>
              ) : permission === "denied" ? (
                <span className="inline-flex items-center gap-1.5 px-3 py-1.5 font-mono text-[10px] uppercase tracking-wider bg-red-500/10 border border-red-500/30 text-red-300 rounded-full" title="Enable notifications in your browser settings">
                  <BellOff className="w-3 h-3" /> Blocked
                </span>
              ) : (
                <button
                  onClick={requestPermission}
                  className="px-3 py-2 text-xs font-mono bg-amber-500/10 border border-amber-500/40 text-amber-300 rounded hover:bg-amber-500/20 transition-colors flex items-center gap-2"
                  data-testid="enable-notifications-btn"
                >
                  <Bell className="w-3.5 h-3.5" />
                  Enable Notifications
                </button>
              )}
            </div>
          </div>

          {activeTab === "active" && (
            <div className="space-y-3">
              {isLoading ? (
                Array.from({ length: 4 }).map((_, i) => (
                  <div key={i} className="bg-white/[0.02] border border-white/10 rounded-lg p-4 flex items-center gap-4">
                    <Skeleton className="w-8 h-8 rounded-full shrink-0" />
                    <div className="flex-1 space-y-2">
                      <Skeleton className="h-4 w-1/2" />
                      <Skeleton className="h-3 w-1/3" />
                    </div>
                    <Skeleton className="h-6 w-12 rounded" />
                    <Skeleton className="h-6 w-6 rounded" />
                  </div>
                ))
              ) : activeAlerts.length === 0 ? (
                <EmptyState
                  icon={Bell}
                  title="No active alerts"
                  description="Set a price alert from any item detail page — you'll be notified when the price crosses your threshold."
                  actions={[{ label: "Browse listings", to: "/listings" }]}
                />
              ) : (
                <>
                  {activeAlerts.length > 1 && (
                    <div className="flex justify-end">
                      <button
                        onClick={dismissAllActive}
                        className="inline-flex items-center gap-1.5 text-xs font-mono text-zinc-400 hover:text-red-400 transition-colors"
                      >
                        <Trash2 className="w-3 h-3" /> Dismiss all
                      </button>
                    </div>
                  )}
                  {activeAlerts.map(({ key, kind, value, enabled }) => {
                    const row = getRow(key);
                    const { Icon: KindIcon, color, bg, border } = alertIcon(kind);
                    return (
                      <div
                        key={key}
                        className="bg-white/[0.02] border border-white/10 rounded-lg p-4 flex items-center gap-4"
                      >
                        <div className={`flex items-center justify-center w-9 h-9 rounded-full ${bg} ${border} border shrink-0`}>
                          <KindIcon className={`w-4 h-4 ${color}`} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="font-mono text-sm truncate">{row?.name || key}</div>
                          <div className={`text-xs mt-0.5 font-mono ${color}`}>
                            {kind === "price_up" ? "Above" : kind === "price_down" ? "Below" : kind} {fmt(value)}
                          </div>
                        </div>
                        <button
                          onClick={() => toggleAlert(key)}
                          className={`p-2 rounded transition-colors ${
                            enabled ? "text-emerald-400 hover:bg-emerald-400/10" : "text-zinc-500 hover:bg-zinc-700/20"
                          }`}
                          aria-label={enabled ? "Disable alert" : "Enable alert"}
                        >
                          <Check className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => removeAlert(key)}
                          className="text-zinc-400 hover:text-red-400 p-2 rounded transition-colors"
                          aria-label="Remove alert"
                        >
                          <XIcon className="w-4 h-4" />
                        </button>
                      </div>
                    );
                  })}
                </>
              )}
            </div>
          )}

          {activeTab === "history" && (
            <div className="space-y-3">
              {isLoading ? (
                Array.from({ length: 3 }).map((_, i) => (
                  <div key={i} className="bg-white/[0.01] border border-white/10 rounded-lg p-4 flex items-center gap-4">
                    <Skeleton className="w-8 h-8 rounded-full shrink-0" />
                    <div className="flex-1 space-y-2">
                      <Skeleton className="h-4 w-1/2" />
                      <Skeleton className="h-3 w-1/3" />
                    </div>
                  </div>
                ))
              ) : historyAlerts.length === 0 ? (
                <EmptyState
                  icon={Bell}
                  title="No alert history"
                  description="Fired price alerts will appear here once they've been triggered."
                />
              ) : (
                <>
                  <div className="flex justify-end">
                    <button
                      onClick={clearHistory}
                      className="inline-flex items-center gap-1.5 text-xs font-mono text-zinc-400 hover:text-red-400 transition-colors"
                    >
                      <Trash2 className="w-3 h-3" /> Clear history
                    </button>
                  </div>
                  {historyAlerts.map(({ key, kind, value, firedAt }) => {
                    const row = getRow(key);
                    const { Icon: KindIcon, color, bg, border } = alertIcon(kind);
                    return (
                      <div
                        key={key}
                        className="bg-white/[0.01] border border-white/10 rounded-lg p-4 flex items-center gap-4 opacity-60"
                      >
                        <div className={`flex items-center justify-center w-9 h-9 rounded-full ${bg} ${border} border shrink-0`}>
                          <KindIcon className={`w-3.5 h-3.5 ${color}`} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="font-mono text-sm text-zinc-400 truncate">{row?.name || key}</div>
                          <div className={`text-xs mt-0.5 font-mono ${color}`}>
                            {kind === "price_up" ? "Above" : kind === "price_down" ? "Below" : kind} {fmt(value)}
                          </div>
                        </div>
                        <div className="font-mono text-[10px] text-zinc-500 whitespace-nowrap">
                          {firedAt ? fmtTime(firedAt) : "—"}
                        </div>
                      </div>
                    );
                  })}
                </>
              )}
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}